# .npmrc at the project root — routes @my-org scoped packages to the private registry
@my-org:registry=https://npm.internal.example.com/
//npm.internal.example.com/:_authToken=${NPM_TOKEN}

{
  "plugins": [
    "node_modules/@example-org/claude-code-security-plugin"
  ]
}

{
  "plugins": [
    "node_modules/@example-org/claude-code-security-plugin",
    "node_modules/@example-org/claude-code-jira-plugin",
    ".claude/plugins/team-custom"
  ]
}

// package-lock.json excerpt
"@example-org/claude-code-security-plugin": {
  "version": "2.1.0",
  "resolved": "https://registry.npmjs.org/@example-org/...",
  "integrity": "sha512-abc123..."
}
